// Process into objects with stable IDs
function makeId(en) {
  return 'oral-' + en.toLowerCase().replace(/['\u2019]+/g, '').replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
}

export const oralPhrases = raw.map(([en, zh, category, sentence, sentenceZh, ja, jaSentence]) => ({
  id: makeId(en),
  en, zh, category,
  img: null,
  level: 'oral',
  sentence, sentenceZh,
  ja, jaSentence,
}));

function shuffleArray(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export const oralPhrasesShuffled = shuffleArray(oralPhrases);
